#include<bits/stdc++.h>
using namespace std;
long long n,a;
int p=0;
int main(){
	cin>>n;
	a=n;
	for(long long i=2;i<=sqrt(n);i++){
		if(a%i==0){
			int s=0;
			while(a%i==0){
				a/=i;
				s++;
			}
			if(p)cout<<"* ";
			if(s!=1)cout<<i<<"^"<<s<<" ",p=1;
			else cout<<i<<" ",p=1;
		}
	}
	if(a!=1){
		if(a!=n)cout<<"* "<<a;
		else cout<<a;
	}
	return 0;
}
